        if not self.tokens:
            raise ValueError("Empty expression")
        self.pos = 0

    def parse(self):
        result = self.parse_expression()
        if self.pos < len(self.tokens):
            raise ValueError("Unexpected tokens after expression")
        return result

    def peek(self):
        return self.tokens[self.pos] if self.pos < len(self.tokens) else None

    def consume(self):
        token = self.peek()
        self.pos += 1
        return token

    # Lowest precedence: addition/subtraction
    def parse_expression(self):
        node = self.parse_term()
        while self.peek() in ('+', '-'):
            op = self.consume()
            right = self.parse_term()
            node = ASTNode('binop', op=op, left=node, right=right)
        return node

    # Higher precedence: multiplication/division
    def parse_term(self):
        node = self.parse_unary()
        while self.peek() in ('*', '/'):
            op = self.consume()
            right = self.parse_unary()
            node = ASTNode('binop', op=op, left=node, right=right)
        return node

    # Unary minus (right-associative)
